// MARK: - API Service
class TradingAPIService {
    static let shared = TradingAPIService()
    
    private let baseURL = "https://api.example.com"
    private let apiKey = "YOUR_API_KEY"
    
    private init() {}
    
    func fetchStocks() async throws -> [Stock] {
        guard let url = URL(string: "\(baseURL)/stocks") else {
            throw URLError(.badURL)
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
        
        let (data, response) = try await URLSession.shared.data(for: request)
        guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
            throw URLError(.badServerResponse)
        }
        
        return try JSONDecoder().decode([Stock].self, from: data)
    }
    
    func executeTrade(_ trade: Trade) async throws -> Trade {
        guard let url = URL(string: "\(baseURL)/trade") else {
            throw URLError(.badURL)
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        request.httpBody = try encoder.encode(trade)
        
        let (data, response) = try await URLSession.shared.data(for: request)
        guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
            throw URLError(.badServerResponse)
        }
        
        return try JSONDecoder().decode(Trade.self, from: data)
    }
}

// MARK: - Trade Execution Manager
class TradeExecutionManager {
    static let shared = TradeExecutionManager()
    
    private init() {}
    
    func executeBuy(symbol: String, quantity: Int, price: Double) async throws -> Trade {
        let trade = Trade(symbol: symbol, quantity: quantity, price: price, type: .buy, timestamp: Date())
        return try await TradingAPIService.shared.executeTrade(trade)
    }
    
    func executeSell(symbol: String, quantity: Int, price: Double) async throws -> Trade {
