        return try await TradingAPIService.shared.executeTrade(trade)
    }
}

// MARK: - Portfolio Manager
class PortfolioManager {
    static let shared = PortfolioManager()
    private let userDefaults = UserDefaults.standard
    private let portfolioKey = "portfolio_items"
    
    private init() {}
    
    func getPortfolio() -> [PortfolioItem] {
        guard let data = userDefaults.data(forKey: portfolioKey),
              let portfolio = try? JSONDecoder().decode([PortfolioItem].self, from: data) else {
            return []
        }
        return portfolio
    }
    
    func updatePortfolio(_ items: [PortfolioItem]) {
        if let data = try? JSONEncoder().encode(items) {
            userDefaults.set(data, forKey: portfolioKey)
        }
    }
    
    func addOrUpdatePosition(symbol: String, quantity: Int, averagePrice: Double, currentPrice: Double) {
        var portfolio = getPortfolio()
        let existingIndex = portfolio.firstIndex { $0.symbol == symbol }
        
        if let index = existingIndex {
            let existing = portfolio[index]
            let totalQuantity = existing.quantity + quantity
            let totalValue = (existing.quantity * existing.averagePrice) + (quantity * averagePrice)
            let newAveragePrice = totalValue / Double(totalQuantity)
            
            portfolio[index] = PortfolioItem(
                symbol: symbol,
                quantity: totalQuantity,
                averagePrice: newAveragePrice,
                currentPrice: currentPrice
            )
        } else {
            portfolio.append(PortfolioItem(
                symbol: symbol,
                quantity: quantity,
                averagePrice: averagePrice,
                currentPrice: currentPrice
            ))
        }
        
        updatePortfolio(portfolio)
    }
}

// MARK: - StockTableViewCell
class StockTableViewCell: UITableViewCell {
    @IBOutlet weak var symbolLabel: UILabel!
    @IBOutlet weak var nameLabel: UILabel!
    @IBOutlet weak var priceLabel: UILabel!
    @IBOutlet weak var changeLabel: UILabel!
    
    func configure(with stock: Stock) {
        symbolLabel.text = stock.symbol
        nameLabel.text = stock.name
        priceLabel.text = String(format: "$%.2f", stock.currentPrice)
        
        if stock.change >= 0 {
            changeLabel.text = String(format: "+%.2f (%.2f%%)", stock.change, stock.changePercent)
            changeLabel.textColor = .systemGreen
        } else {
            changeLabel.text = String(format: "-%.2f (%.2f%%)", abs(stock.change), abs(stock.changePercent))
            changeLabel.textColor = .systemRed
        }
    }
}

// MARK: - PortfolioTableViewCell
class PortfolioTableViewCell: UITableViewCell {
    @IBOutlet weak var symbolLabel: UILabel!
    @IBOutlet weak var quantityLabel: UILabel!
    @IBOutlet weak var averagePriceLabel: UILabel!
    @IBOutlet weak var currentValueLabel: UILabel!
    @IBOutlet weak var profitLabel: UILabel!
    
    func configure(with item: PortfolioItem) {
        symbolLabel.text = item.symbol
        quantityLabel.text = "\(item.quantity)"
        averagePriceLabel.text = String(format: "$%.2f", item.averagePrice)
        currentValueLabel.text = String(format: "$%.2f", item.currentPrice)
        
        let currentValue = Double(item.quantity) * item.currentPrice
        let investedValue = Double(item.quantity) * item.averagePrice
        let profit = currentValue - investedValue
        
        if profit >= 0 {
            profitLabel.text = String(format: "+$%.2f", profit)
            profitLabel.textColor = .systemGreen
        } else {
            profitLabel.text = String(format: "-$%.2f", abs(profit))
            profitLabel.textColor = .systemRed
        }
    }
}

// MARK: - StocksViewController
class StocksViewController: UIViewController {
    @IBOutlet weak var tableView: UITableView!
    
