        super.viewDidLoad()
        setupUI()
    }
    
    private func setupUI() {
        title = "Trade"
        symbolLabel.text = stock.symbol
        currentPriceLabel.text = String(format: "$%.2f", stock.currentPrice)
        quantityTextField.placeholder = "Quantity"
        quantityTextField.keyboardType = .numberPad
        
        buyButton.backgroundColor = .systemGreen
        buyButton.setTitleColor(.white, for: .normal)
        sellButton.backgroundColor = .systemRed
        sellButton.setTitleColor(.white, for: .normal)
    }
    
    @IBAction func buyButtonTapped(_ sender: UIButton) {
        executeTrade(type: .buy)
    }
    
    @IBAction func sellButtonTapped(_ sender: UIButton) {
        executeTrade(type: .sell)
    }
    
    private func executeTrade(type: TradeType) {
        guard let quantityString = quantityTextField.text, let quantity = Int(quantityString) else {
            showAlert(message: "Please enter a valid quantity")
            return
        }
        
        Task {
            do {
                let trade = try await TradeExecutionManager.shared.executeBuy(symbol: stock.symbol, quantity: quantity, price: stock.currentPrice)
                await MainActor.run {
                    showAlert(message: "Trade executed successfully!")
                    navigationController?.popViewController(animated: true)
                }
